#include "fgbg.h"
void pfg(const char*c){int p;sscanf(c,"fg %d",&p);int f=0;for(int i=0;i<MAX_PROCS;i++){if(processes[i].pid==p&&processes[i].pid!=shell_pid){f=1;tcsetpgrp(STDIN_FILENO,p);if(processes[i].state==2)kill(p,SIGCONT);processes[i].state=0;int st;struct timeval s,e;sfp(p);gettimeofday(&s,NULL);waitpid(p,&st,WUNTRACED);gettimeofday(&e,NULL);sfp(0);if(WIFEXITED(st)||WIFSIGNALED(st)){processes[i].state=1;processes[i].end_time=time(NULL);}else if(WIFSTOPPED(st))processes[i].state=2;time_monitor(s,e,"fg");signal(SIGTTOU,SIG_IGN);tcsetpgrp(STDIN_FILENO,shell_pid);signal(SIGTTOU,SIG_DFL);return;}}if(!f)printf("No such process found\n");}
void pbg(const char*c){int p;sscanf(c,"bg %d",&p);int f=0;for(int i=0;i<MAX_PROCS;i++){if(processes[i].pid==p){f=1;if(processes[i].state==2){kill(p,SIGCONT);processes[i].state=1;printf("Process %d resumed\n",p);}else printf("Process %d already running\n",p);break;}}if(!f)printf("No such process found\n");}
